css:
@page {
	size: A4 portrait;
	margin: 10mm 12mm 10mm 12mm;
}

.print-format {
	padding: 0 !important;
	margin: 0 !important;
	font-family: Arial, Helvetica, sans-serif !important;
	font-size: 9px !important;
	color: #000 !important;
	background: #fff !important;
}

.print-format p {
	margin: 0;
}

.nutc-safety-briefing {
	width: 184mm;
	margin: 0 auto;
	color: #000;
}

/* Logo */
.nutc-logo-wrap {
	text-align: center;
	margin: 0 0 3px 0;
	padding: 0;
}

.nutc-logo-wrap img,
.nutc-logo {
	max-width: 115px !important;
	max-height: 38px !important;
	height: auto !important;
	object-fit: contain;
}

/* Title */
.h2s-title-row {
	width: 100%;
	text-align: center;
	font-weight: 700;
	font-size: 15px;
	line-height: 1.15;
	margin: 0 0 6px 0;
	padding: 0;
}

.h2s-title {
	display: inline-block;
	margin-right: 18px;
	letter-spacing: 0.2px;
}

.h2s-course-codes {
	display: inline-block;
	font-size: 15px;
	font-weight: 700;
}

/* Table Common */
.nutc-table {
	width: 100%;
	border-collapse: collapse !important;
	table-layout: fixed;
	margin: 0;
	padding: 0;
}

.nutc-table th,
.nutc-table td {
	border: 1px solid #000 !important;
	padding: 2px 4px !important;
	vertical-align: top;
	color: #000 !important;
	line-height: 1.12;
	word-wrap: break-word;
	overflow-wrap: break-word;
}

.nutc-table th {
	font-weight: 700;
	text-align: center;
}

/* Grey Headers */
.header-row th {
	background: #e6e6e6 !important;
}

.disc-title-line {
	font-size: 9.5px;
	font-weight: 700;
	text-align: center;
	line-height: 1.05;
}

.disc-sub-line {
	font-size: 9px;
	font-weight: 700;
	text-align: center;
	line-height: 1.05;
}

/* Basic H2S Discussion */
.nutc-discussion-h2s td {
	font-size: 8.6px;
}

.discussion-sr {
	width: 5%;
	text-align: center;
	vertical-align: middle !important;
}

.discussion-text {
	width: 91%;
}

.col-yn {
	width: 4%;
	text-align: center;
	vertical-align: middle !important;
	font-weight: 700;
}

/* Practical H2S */
.nutc-practical-h2s th,
.nutc-practical-h2s td {
	font-size: 8.6px;
}

.col-exercise-h2s {
	width: 38%;
}

.col-risk-h2s {
	width: 58%;
}

.small-list {
	margin: 0;
	padding-left: 16px;
}

.small-list li {
	margin: 0;
	padding: 0;
	line-height: 1.12;
}

/* Attendees */
.nutc-attendees {
	margin-top: 0;
}

.header-yellow th {
	background: #ffff99 !important;
	font-size: 10px;
	font-weight: 700;
	text-align: center;
	vertical-align: middle !important;
	padding: 3px 4px !important;
}

.nutc-attendees td {
	height: 14.5px;
	font-size: 8.6px;
	vertical-align: middle !important;
	padding-top: 1px !important;
	padding-bottom: 1px !important;
	line-height: 1.05;
}

.col-sr {
	width: 7%;
	text-align: center;
}

.col-name {
	width: 36%;
}

.col-company {
	width: 31%;
}

.col-signed {
	width: 26%;
	text-align: center;
}

.col-sign {
	text-align: center;
}

/* Bottom Agenda */
.agenda-bottom {
	margin: 0;
	padding: 4px;
	border-left: 1px solid #000;
	border-right: 1px solid #000;
	border-bottom: none;
	font-size: 10px;
	line-height: 1.15;
	text-align: center;
}

/* Instructor Single */
.nutc-instructor-single {
	margin-top: 0;
}

.nutc-instructor-single th,
.nutc-instructor-single td {
	font-size: 10px;
	height: 15px;
	vertical-align: middle !important;
	padding: 2px 4px !important;
}

.nutc-instructor-single th {
	text-align: center;
	font-weight: 700;
}

.nutc-instructor-single td {
	text-align: center;
}

/* Signature */
.sig-img {
	max-height: 22px !important;
	max-width: 95px !important;
	object-fit: contain;
}

/* Footer */
.form-footer {
	margin-top: 42px;
	font-size: 8px;
	width: 100%;
	line-height: 1;
	color: #000;
}

.form-footer:after {
	content: "";
	display: table;
	clear: both;
}

.form-footer span:first-child {
	float: left;
}

.page-text {
	float: right;
}

/* Other Briefing Types */
.form-ref-top {
	font-size: 9px;
	margin-bottom: 4px;
}

.agenda-top {
	font-size: 10px;
	text-align: center;
	margin-bottom: 6px;
	font-weight: 700;
}

.date-single {
	font-size: 10px;
	margin-bottom: 5px;
}

.nutc-dates td {
	font-size: 9px;
	height: 18px;
	vertical-align: middle !important;
}

.nutc-instructors th,
.nutc-instructors td,
.nutc-discussion th,
.nutc-discussion td,
.nutc-practical th,
.nutc-practical td {
	font-size: 8.8px;
}

.col-exercise {
	width: 27%;
}

.col-risk {
	width: 58%;
}

.sub-head {
	font-size: 8px;
	font-weight: 400;
}

/* Print Color */
* {
	-webkit-print-color-adjust: exact !important;
	print-color-adjust: exact !important;
}

/* Avoid weird page split */
.nutc-table,
.nutc-table tr,
.nutc-table td,
.nutc-table th {
	page-break-inside: avoid !important;
}
